question:
Considering the code below, what will be logged to the console after the button is clicked? 

```javascript
function Component() {
  const [value, setValue] = useState(0);

  const handleClick = () => {
    setValue(value + 1);
    console.log(value);
    setValue(value + 1);
    console.log(value);
  };

  return <button onClick={handleClick}>Click</button>;
}
```
